import React, { useEffect, useState } from 'react';
import { Table, Button, Popconfirm, Modal, message, Avatar, Space, Layout, Menu, Form, Input, Row, Col, Typography, Tooltip, Dropdown } from 'antd';
import { EditOutlined, DeleteOutlined, EyeOutlined, QrcodeOutlined, DownloadOutlined, MoreOutlined, UserOutlined } from '@ant-design/icons';
import { logout } from '../utils/auth';
import { useNavigate } from 'react-router-dom';
import { uploadToCloudinary } from '../utils/cloudinary';

const { Sider, Content, Header } = Layout;
const { Title, Text } = Typography;

export default function ViewAllUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [editForm] = Form.useForm();
  const [editLoading, setEditLoading] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  const email = localStorage.getItem('adminEmail') || 'Super Admin';
  const navigate = useNavigate();
  const [editProfilePic, setEditProfilePic] = useState(null);
  const [editPreview, setEditPreview] = useState('');

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) setUsers(data);
      else message.error(data.message || 'Failed to fetch users');
    } catch (err) {
      message.error('Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { 
    fetchUsers(); 
    // Check screen size and collapse sidebar if needed
    const handleResize = () => {
      if (window.innerWidth < 1024) {
        setIsSidebarCollapsed(true);
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleDelete = async (id) => {
    const token = localStorage.getItem('token');
    try {
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User deleted');
        setUsers(users.filter(u => u._id !== id));
      } else {
        message.error(data.message || 'Failed to delete user');
      }
    } catch (err) {
      message.error('Failed to delete user');
    }
  };

  const handleEdit = (user) => {
    setEditingUser(user);
    setEditModalVisible(true);
    setEditProfilePic(null);
    setEditPreview(user.profilePic || '');
    editForm.setFieldsValue({
      name: user.name || '',
      email: user.email || '',
      phoneNumber: user.phoneNumber || '',
      nic: user.nic || '',
      school: user.school || '',
      age: user.age || ''
    });
  };

  const handleEditModalClose = () => {
    setEditModalVisible(false);
    editForm.resetFields();
    setEditProfilePic(null);
    setEditPreview('');
    setEditLoading(false);
  };

  const handleEditFileChange = e => {
    const file = e.target.files[0];
    setEditProfilePic(file || null);
    setEditPreview(file ? URL.createObjectURL(file) : (editingUser?.profilePic || ''));
  };

  const handleEditSubmit = async () => {
    try {
      setEditLoading(true);
      const values = await editForm.validateFields();
      let profilePicUrl = editingUser.profilePic;

      if (editProfilePic) {
        try {
          profilePicUrl = await uploadToCloudinary(editProfilePic);
        } catch (uploadError) {
          message.error('Failed to upload profile picture');
          setEditLoading(false);
          return;
        }
      }

      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${editingUser._id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ ...values, profilePic: profilePicUrl }),
      });

      const data = await res.json();
      if (res.ok) {
        message.success('User updated successfully');
        setEditModalVisible(false);
        setTimeout(fetchUsers, 500);
      } else {
        message.error(data.message || 'Failed to update user');
      }
    } catch (err) {
      if (err.errorFields) {
        message.error('Please check the form fields');
      } else {
        message.error('Failed to update user');
      }
    } finally {
      setEditLoading(false);
    }
  };

  const handleResendQR = async (userId, userName) => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${userId}/resend-qr`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });
      const data = await res.json();
      if (res.ok) {
        message.success(`QR code sent to ${userName}'s email successfully!`);
      } else {
        message.error(data.message || 'Failed to send QR code');
      }
    } catch (err) {
      message.error('Failed to send QR code');
    }
  };

  const columns = [
    { 
      title: 'ID', 
      dataIndex: '_id', 
      key: '_id',
      responsive: ['lg'],
      render: (id) => <span className="text-xs font-mono bg-gray-100 px-2 py-1 rounded">{id.substring(0, 8)}...</span>
    },
    { 
      title: 'Name', 
      dataIndex: 'name', 
      key: 'name',
      render: (name) => <span className="font-medium text-gray-800">{name}</span>
    },
    { 
      title: 'Email', 
      dataIndex: 'email', 
      key: 'email',
      responsive: ['lg'],
      render: (email) => <span className="text-gray-600">{email}</span>
    },
    { 
      title: 'Phone', 
      dataIndex: 'phoneNumber', 
      key: 'phoneNumber',
      responsive: ['lg'],
      render: (phone) => <span>{phone}</span>
    },
    { 
      title: 'NIC', 
      dataIndex: 'nic', 
      key: 'nic',
      responsive: ['lg'],
      render: (nic) => <span className="font-mono bg-gray-100 px-2 py-1 rounded">{nic}</span>
    },
    { 
      title: 'Profile', 
      dataIndex: 'profilePic', 
      key: 'profilePic',
      render: url => (
        <div className="transition-transform duration-300 hover:scale-110">
          {url ? (
            <Avatar src={url} size={32} className="ring-2 ring-blue-500" />
          ) : (
            <Avatar icon={<UserOutlined />} size={32} className="bg-blue-100 text-blue-600" />
          )}
        </div>
      )
    },
    {
      title: 'Actions',
      key: 'actions',
      fixed: 'right',
      width: 150,
      render: (_, user) => {
        const actionItems = [
          {
            key: 'view',
            label: 'View Profile',
            icon: <EyeOutlined />, 
            onClick: () => window.open(`${process.env.REACT_APP_API_URL || ''}/user/${user._id}`, '_blank')
          },
          {
            key: 'edit',
            label: 'Edit User',
            icon: <EditOutlined />, 
            onClick: () => handleEdit(user)
          },
          {
            key: 'resend',
            label: 'Resend QR Code',
            icon: <QrcodeOutlined />, 
            onClick: () => handleResendQR(user._id, user.name)
          },
          {
            key: 'delete',
            label: 'Delete User',
            icon: <DeleteOutlined />, 
            danger: true,
            onClick: () => handleDelete(user._id)
          }
        ];

        return (
          <div className="flex space-x-2">
            <Tooltip title="View Profile">
              <Button 
                icon={<EyeOutlined />} 
                size="small"
                className="hidden md:inline-flex items-center justify-center transition-all hover:bg-blue-50 hover:text-blue-600"
                onClick={() => window.open(`${process.env.REACT_APP_API_URL || ''}/user/${user._id}`, '_blank')}
              />
            </Tooltip>
            <Tooltip title="Edit User">
              <Button 
                icon={<EditOutlined />} 
                size="small"
                className="hidden md:inline-flex items-center justify-center transition-all hover:bg-green-50 hover:text-green-600"
                onClick={() => handleEdit(user)}
              />
            </Tooltip>
            <Tooltip title="Resend QR Code">
              <Button 
                icon={<QrcodeOutlined />} 
                size="small"
                className="hidden md:inline-flex items-center justify-center transition-all hover:bg-purple-50 hover:text-purple-600"
                onClick={() => handleResendQR(user._id, user.name)}
              />
            </Tooltip>
            <Popconfirm 
              title="Delete user?" 
              description="This action cannot be undone."
              onConfirm={() => handleDelete(user._id)} 
              okText="Yes" 
              cancelText="No"
              okType="danger"
            >
              <Button 
                icon={<DeleteOutlined />} 
                danger 
                size="small"
                className="hidden md:inline-flex items-center justify-center transition-all hover:bg-red-50"
              />
            </Popconfirm>
            <Dropdown
              menu={{ items: actionItems }}
              trigger={['click']}
              placement="bottomRight"
              className="md:hidden"
            >
              <Button 
                icon={<MoreOutlined />} 
                size="small"
                className="inline-flex md:hidden items-center justify-center"
              />
            </Dropdown>
          </div>
        );
      },
    },
  ];

  return (
    <Layout className="min-h-screen bg-gray-50">
      <Sider 
        collapsible
        collapsed={isSidebarCollapsed}
        onCollapse={(collapsed) => setIsSidebarCollapsed(collapsed)}
        breakpoint="lg"
        collapsedWidth="80"
        width="250"
        className="!fixed h-full z-10 shadow-lg transition-all duration-300"
      >
        <div className="flex flex-col h-full">
          <div className="p-4 flex justify-center">
            <img
              src={process.env.PUBLIC_URL + '/IMG-20230930-WA0000-removebg-preview.png'}
              alt="Scout Logo"
              className="w-16 h-16 object-contain transition-all duration-300"
            />
          </div>
          <Menu
            theme="dark"
            mode="inline"
            defaultSelectedKeys={['view-all-users']}
            onClick={({ key }) => {
              if (key === 'overview') navigate('/dashboard/super');
              if (key === 'add') navigate('/dashboard/super/add-user');
              if (key === 'view-all-users') navigate('/dashboard/super/view-all-users');
              if (key === 'update-duty') navigate('/dashboard/super/update-duty');
              if (key === 'attendance-history') navigate('/dashboard/super/attendance-history');
            }}
            items={[
              { 
                key: 'overview', 
                label: <span className="text-sm">Overview</span>,
                className: "hover:bg-blue-700 transition-colors"
              },
              { 
                key: 'add', 
                label: <span className="text-sm">Add New User</span>,
                className: "hover:bg-blue-700 transition-colors"
              },
              { 
                key: 'view-all-users', 
                label: <span className="text-sm">View All Users</span>,
                className: "hover:bg-blue-700 transition-colors bg-blue-800"
              },
              { 
                key: 'update-duty', 
                label: <span className="text-sm">Update Duty Times</span>,
                className: "hover:bg-blue-700 transition-colors"
              },
              { 
                key: 'attendance-history', 
                label: <span className="text-sm">Attendance History</span>,
                className: "hover:bg-blue-700 transition-colors"
              },
            ]}
            className="flex-1"
          />
        </div>
      </Sider>

      <Layout className={`transition-all duration-300 ${isSidebarCollapsed ? 'ml-20' : 'ml-64'}`}>
        <Header className="bg-white shadow-sm flex justify-between items-center px-6 fixed w-full z-10">
          <div className="flex items-center">
            <span className="font-medium text-gray-800">{email}</span>
            <span className="ml-3 px-2 py-1 bg-blue-100 text-blue-600 text-xs rounded-full">super</span>
          </div>
          <Button 
            type="primary" 
            danger 
            onClick={logout}
            className="hover:scale-105 transition-transform"
          >
            Logout
          </Button>
        </Header>

        <Content className="mt-16 p-6">
          <div className="bg-white rounded-xl shadow-sm p-6 animate-fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6">
              <div className="mb-4 md:mb-0">
                <h2 className="text-2xl font-bold text-gray-800">All Users</h2>
                <p className="text-gray-500">{users.length} users found</p>
              </div>
              <Button 
                type="primary" 
                icon={<DownloadOutlined />}
                className="flex items-center hover:scale-105 transition-transform"
                onClick={() => {
                  const csvContent = [
                    ['User ID', 'Name', 'Email', 'Phone Number', 'NIC', 'Profile Picture URL'],
                    ...users.map(user => [
                      user._id,
                      user.name || '',
                      user.email || '',
                      user.phoneNumber || '',
                      user.nic || '',
                      user.profilePic || ''
                    ])
                  ].map(row => row.join(',')).join('\n');

                  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                  const link = document.createElement('a');
                  const url = URL.createObjectURL(blob);
                  link.setAttribute('href', url);
                  link.setAttribute('download', `all_users_${new Date().toISOString().split('T')[0]}.csv`);
                  link.style.visibility = 'hidden';
                  document.body.appendChild(link);
                  link.click();
                  document.body.removeChild(link);
                }}
              >
                Export to CSV
              </Button>
            </div>

            <div className="overflow-x-auto">
              <Table 
                columns={columns} 
                dataSource={users} 
                rowKey="_id" 
                loading={loading}
                scroll={{ x: 1200 }}
                pagination={{
                  showSizeChanger: true,
                  showQuickJumper: true,
                  showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} users`,
                  pageSizeOptions: ['10', '20', '50', '100'],
                  responsive: true
                }}
                className="ant-table-striped"
                rowClassName={(record, index) => index % 2 === 0 ? 'bg-white' : 'bg-gray-50'}
              />
            </div>
          </div>

          <Modal
            title={<span className="text-xl font-semibold text-gray-800">Edit User</span>}
            open={editModalVisible}
            onCancel={handleEditModalClose}
            onOk={handleEditSubmit}
            okText="Save Changes"
            cancelText="Cancel"
            confirmLoading={editLoading}
            width={600}
            destroyOnClose
            footer={[
              <Button key="back" onClick={handleEditModalClose} className="hover:bg-gray-100">
                Cancel
              </Button>,
              <Button 
                key="submit" 
                type="primary" 
                loading={editLoading} 
                onClick={handleEditSubmit}
                className="bg-blue-600 hover:bg-blue-700"
              >
                Save Changes
              </Button>,
            ]}
            className="rounded-lg"
          >
            <Form
              form={editForm}
              layout="vertical"
              autoComplete="off"
              className="mt-6"
            >
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <Form.Item
                  label={<span className="font-medium text-gray-700">Name</span>}
                  name="name"
                  rules={[{ required: true, message: 'Please enter name' }]}
                >
                  <Input 
                    placeholder="Enter name" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>

                <Form.Item
                  label={<span className="font-medium text-gray-700">Email</span>}
                  name="email"
                  rules={[
                    { required: true, message: 'Please enter email' },
                    { type: 'email', message: 'Please enter a valid email' }
                  ]}
                >
                  <Input 
                    placeholder="Enter email" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>

                <Form.Item
                  label={<span className="font-medium text-gray-700">Phone Number</span>}
                  name="phoneNumber"
                  rules={[{ required: true, message: 'Please enter phone number' }]}
                >
                  <Input 
                    placeholder="Enter phone number" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>

                <Form.Item
                  label={<span className="font-medium text-gray-700">NIC</span>}
                  name="nic"
                  rules={[{ required: true, message: 'Please enter NIC' }]}
                >
                  <Input 
                    placeholder="Enter NIC" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>

                <Form.Item
                  label={<span className="font-medium text-gray-700">School</span>}
                  name="school"
                  rules={[{ required: false }]}
                >
                  <Input 
                    placeholder="Enter school" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>

                <Form.Item
                  label={<span className="font-medium text-gray-700">Age</span>}
                  name="age"
                  rules={[{ required: false, type: 'number', min: 1, max: 120, message: 'Please enter a valid age' }]}
                >
                  <Input 
                    type="number" 
                    placeholder="Enter age" 
                    className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-colors"
                  />
                </Form.Item>
              </div>

              <Form.Item 
                label={<span className="font-medium text-gray-700">Profile Photo</span>}
                className="mt-4"
              >
                <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                  <label className="flex-1">
                    <div className="relative cursor-pointer">
                      <input 
                        type="file" 
                        accept="image/*" 
                        onChange={handleEditFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      />
                      <div className="py-2 px-4 border border-gray-300 rounded-lg hover:border-blue-400 transition-colors text-center">
                        <span className="text-gray-600">Choose new photo</span>
                      </div>
                    </div>
                  </label>
                  {editPreview && (
                    <div className="relative group">
                      <Avatar 
                        src={editPreview} 
                        size={64} 
                        icon={<UserOutlined />} 
                        className="ring-2 ring-blue-400 transition-transform group-hover:scale-110"
                      />
                      {editProfilePic && (
                        <span className="absolute -top-2 -right-2 bg-green-500 text-white text-xs rounded-full px-2 py-1 animate-pulse">
                          New
                        </span>
                      )}
                    </div>
                  )}
                </div>
                <p className="text-gray-500 text-xs mt-2">
                  Leave empty to keep current profile picture
                </p>
              </Form.Item>
            </Form>
          </Modal>
        </Content>
      </Layout>
    </Layout>
  );
}
